#ifndef BATT_STRONG_TYPEDEF_HPP
#define BATT_STRONG_TYPEDEF_HPP

#include <batteries/config.hpp>
//

#include <batteries/type_traits.hpp>

#include <functional>
#include <type_traits>

// Must be outside namespace batt so we can do ADL.
//
inline constexpr std::false_type batt_strong_typedef_supports_numerics(...)
{
    return {};
}

namespace batt {

// Forward-declaration.
//
template <typename T, typename Tag>
class StrongType;

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T>
struct IsStrongType : std::false_type {
};

// IsStrongType: true case
//
template <typename T, typename Tag>
struct IsStrongType<StrongType<T, Tag>> : std::true_type {
};

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <typename T>
inline constexpr bool is_strong_type(StaticType<T> = {}) noexcept
{
    return IsStrongType<T>::value;
}

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename PrimitiveT, typename Tag>
struct StrongTypeHash {
    using result_type = typename std::hash<PrimitiveT>::result_type;

    template <typename T>
    result_type operator()(const StrongType<T, Tag>& obj) const
    {
        return this->impl_(obj.primitive_value());
    }

   private:
    std::hash<PrimitiveT> impl_;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T, typename Tag>
class StrongType
{
    static_assert(std::is_standard_layout<T>{} && std::is_trivial<T>{}, "`T` must be a POD type.");

   public:
    using value_type = T;
    using primitive_type = T;
    using tag_type = Tag;

    using Hash = StrongTypeHash<T, Tag>;

    struct Delta;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    constexpr StrongType() noexcept : value_{strong_typedef_default_value((Tag*)nullptr)}
    {
    }

    explicit constexpr StrongType(T init_value) noexcept : value_{init_value}
    {
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    constexpr value_type value() const noexcept
    {
        return this->value_;
    }

    constexpr primitive_type primitive_value() const noexcept
    {
        return this->value();
    }

    constexpr operator value_type() const noexcept
    {
        return this->value();
    }

    StrongType& operator+=(Delta d) noexcept;
    StrongType& operator-=(Delta d) noexcept;

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    T value_;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T, typename InnerTag, typename OuterTag>
class StrongType<StrongType<T, InnerTag>, OuterTag>
{
    static_assert(std::is_standard_layout<T>{} && (std::is_trivial<T>{} || IsStrongType<T>{}),
                  "`T` must be a POD type (including another strong type).");

   public:
    using value_type = StrongType<T, InnerTag>;
    using primitive_type = typename value_type::primitive_type;
    using tag_type = OuterTag;

    using Hash = StrongTypeHash<T, OuterTag>;

    struct Delta;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    constexpr StrongType() noexcept : value_{strong_typedef_default_value((OuterTag*)nullptr)}
    {
    }

    explicit constexpr StrongType(value_type init_value) noexcept : value_{init_value}
    {
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    constexpr value_type value() const noexcept
    {
        return this->value_;
    }

    constexpr primitive_type primitive_value() const noexcept
    {
        return this->value_.primitive_value();
    }

    constexpr operator value_type() const noexcept
    {
        return this->value();
    }

    constexpr operator primitive_type() const noexcept
    {
        return this->primitive_value();
    }

    StrongType& operator+=(Delta d) noexcept;
    StrongType& operator-=(Delta d) noexcept;

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    value_type value_;
};

template <typename T, typename Tag>
struct StrongType<T, Tag>::Delta : StrongType<T, Tag> {
    using StrongType::StrongType;

    /*implicit*/ Delta(StrongType value) noexcept : StrongType{value}
    {
    }
};

#define BATT_STRONG_TYPEDEF_PASTE_2_(a, b) a##b
#define BATT_STRONG_TYPEDEF_PASTE_(a, b) BATT_STRONG_TYPEDEF_PASTE_2_(a, b)

#define BATT_STRONG_TYPEDEF(TYPE, NAME) BATT_STRONG_TYPEDEF_WITH_DEFAULT(TYPE, NAME, TYPE{})

#define BATT_STRONG_TYPEDEF_WITH_DEFAULT(TYPE, NAME, VALUE)                                                  \
    struct BATT_STRONG_TYPEDEF_PASTE_(NAME, _TAG);                                                           \
    [[maybe_unused]] inline constexpr TYPE strong_typedef_default_value(                                     \
        BATT_STRONG_TYPEDEF_PASTE_(NAME, _TAG)*) noexcept                                                    \
    {                                                                                                        \
        return VALUE;                                                                                        \
    }                                                                                                        \
    using NAME = ::batt::StrongType<TYPE, BATT_STRONG_TYPEDEF_PASTE_(NAME, _TAG)>

#define BATT_STRONG_TYPEDEF_SUPPORTS_NUMERICS(NAME)                                                          \
    inline constexpr std::true_type batt_strong_typedef_supports_numerics(                                   \
        BATT_STRONG_TYPEDEF_PASTE_(NAME, _TAG)*)                                                             \
    {                                                                                                        \
        return {};                                                                                           \
    }

#define BATT_STRONG_TYPEDEF_NUMERIC_OPERATOR_DEFN(op_long, op_short)                                         \
    template <typename T, typename Tag,                                                                      \
              typename = std::enable_if_t<batt_strong_typedef_supports_numerics((Tag*)nullptr)>>             \
    constexpr StrongType<T, Tag> op_long(StrongType<T, Tag> a, StrongType<T, Tag> b) noexcept                \
    {                                                                                                        \
        return StrongType<T, Tag>{a.value() op_short b.value()};                                             \
    }

BATT_STRONG_TYPEDEF_NUMERIC_OPERATOR_DEFN(operator+, +)
BATT_STRONG_TYPEDEF_NUMERIC_OPERATOR_DEFN(operator-, -)
BATT_STRONG_TYPEDEF_NUMERIC_OPERATOR_DEFN(operator*, *)
BATT_STRONG_TYPEDEF_NUMERIC_OPERATOR_DEFN(operator/, /)

template <typename T, typename Tag>
inline StrongType<T, Tag>& StrongType<T, Tag>::operator+=(Delta d) noexcept
{
    static_assert(batt_strong_typedef_supports_numerics((Tag*)nullptr),
                  "This StrongType does not support numeric operations; see "
                  "BATT_STRONG_TYPEDEF_SUPPORTS_NUMERICS");

    value_ += d;

    return *this;
}

template <typename T, typename Tag>
inline StrongType<T, Tag>& StrongType<T, Tag>::operator-=(Delta d) noexcept
{
    static_assert(batt_strong_typedef_supports_numerics((Tag*)nullptr),
                  "This StrongType does not support numeric operations; see "
                  "BATT_STRONG_TYPEDEF_SUPPORTS_NUMERICS");

    value_ -= d;

    return *this;
}

}  // namespace batt

#endif  // BATT_STRONG_TYPEDEF_HPP
